To find the shell widget, we can use gdk_window_get_toplevel() to avoid
repeatedly retrieving user_data by gdk_window_get_user_data() and
gtk_object_get_data():


static nsWidget *
GetShellWidget(GdkWindow *gdkWindow)
{
  GdkWindow *parent = gdk_window_get_toplevel(gdkWindow);
  nsWidget *root_win = nsnull;
  gpointer data;

  if (parent != gdkWindow) {
    gdk_window_get_user_data(parent, &data);
    if (GTK_IS_OBJECT(data)) {
      root_win = (nsWidget *) gtk_object_get_data(GTK_OBJECT(data), "nsWindow");
      if (root_win)
        return root_win;
    }
  }
  return nsnull;
}

