To wit:
    var VERSION = "JS_12";

    .
    .
    .
    if ( typeof version == "function" ) {
        writeLineToLog("version 120");
        version(120);
        VERSION = "120";
    } else {
        writeLineToLog(typeof version);
        function version() { return 0; };
    }

    testcases[tc++] = new TestCase ( SECTION,
        "a.toString()",
