            a.toString() );

The current Interpreter creates a version() function always, and then
runs the test to see if one already exists, which is the wrong order,
sadly.

In the new JS 1.5 engine, if you have a JSObject * locked with JS_LockGCThing(),
no finalize routines for any objects will be called when the context is
destroyed. This is different from JS 1.4 where the finalize routines will be
called as expected.

Here's a test program as you requested in the new group (apologies for the
length)
--------------------------------------------------------------------
#include <iostream.h>
#include <stdlib.h>

/* These defines needed before including jsapi.h */
#define JS_THREADSAFE   1
#define XP_UNIX     1

#include <jsapi.h>

/* # of bytes allocated on stack at time */
#define JS_STACK_CHUNK_SIZE           8192

/* Max # of bytes allocatable by javascript runtime environment */
#define JS_MAX_BYTES     8L*1024L*1024L


static void CSDQLNode_JSFinalize( JSContext *cx, JSObject *obj );
static void global_JSFinalize( JSContext *cx, JSObject *obj );
static JSBool CSDQLNode_getProperty( JSContext *cx, JSObject *ob,
                                     jsval id, jsval *vp );

enum CSDQLNode_ids {
    CSDQLNODE_DBCONN
};

static JSPropertySpec CSDQLNode_properties[] = {
    {"DBConn",    CSDQLNODE_DBCONN,    JSPROP_READONLY},
    {0}
};

JSClass CSDQLNode_class = {
    "CSDQLNode", JSCLASS_HAS_PRIVATE,
    JS_PropertyStub,  JS_PropertyStub, (JSPropertyOp)CSDQLNode_getProperty,
    JS_PropertyStub, JS_EnumerateStub, JS_ResolveStub, JS_ConvertStub, 
    CSDQLNode_JSFinalize
};


JSClass global_class = {
    "global", 0,
    JS_PropertyStub,  JS_PropertyStub,  JS_PropertyStub,  JS_PropertyStub,
    JS_EnumerateStub, JS_ResolveStub,   JS_ConvertStub,   global_JSFinalize
};

static void CSDQLNode_JSFinalize( JSContext *cx, JSObject *obj ) {
    JSObject *ob;

    fprintf( stderr, "CSDQLNode (%p) finalize called\n", obj );
    if( ( ob = (JSObject *)JS_GetPrivate( cx, obj ) ) ) {
        fprintf( stderr, "Unlocking cached ob\n" );
        JS_UnlockGCThing( cx, ob );
    }
}

static void global_JSFinalize( JSContext *cx, JSObject *obj ) {
    fprintf( stderr, "global (%p) finalize called\n", obj );
}


static JSBool CSDQLNode_getProperty( JSContext *cx, JSObject *ob,
                                     jsval id, jsval *vp ) {
    JSBool    ret     = JS_FALSE;
    JSObject *retOb;

    if( JSVAL_IS_INT( id ) ) {
        switch( JSVAL_TO_INT( id ) ) {
            case CSDQLNODE_DBCONN:
                fprintf( stderr, "Getting dbconn\n" );
                if( !( retOb = (JSObject *)JS_GetPrivate( cx, ob ) ) ) {
                    retOb = JS_NewObject( cx, &CSDQLNode_class, NULL, NULL );
                    JS_DefineProperties( cx, retOb, CSDQLNode_properties );
#if 1
                    JS_LockGCThing( cx, (void *)retOb );
#endif
                    JS_SetPrivate( cx, ob, retOb );
                }
                *vp = OBJECT_TO_JSVAL( retOb );
                break;
        }
    }
    ret = JS_TRUE;
    return ret;
}

int main( int argc, char *argv[] ) {
    JSRuntime *JSRT;
    JSContext *cx;
    JSObject  *ob, *ob2;
    jsval      rval;
    char *script = "var a = CSDQLNode.DBConn";

    JSRT = JS_Init( JS_MAX_BYTES );
    cx = JS_NewContext( JSRT, JS_STACK_CHUNK_SIZE );
    ob = JS_NewObject( cx, &global_class, 0, 0 );
    JS_InitStandardClasses( cx, ob );
    ob2 = JS_DefineObject( cx, ob, "CSDQLNode",
                           &CSDQLNode_class, NULL, 0 );
    JS_DefineProperties( cx, ob2, CSDQLNode_properties );
    JS_EvaluateScript( cx, ob, script,
                       strlen( script ), "", 0, &rval );
    JS_DestroyContext( cx );
    JS_Finish( JSRT );
    return 0;
}

