//-------------------------------------------------------------------------------
---------
nsresult nsFileSpec::Truncate(PRInt32 aNewLength) const
//-------------------------------------------------------------------------------
---------
{
	short	refNum;
	OSErr	err;

	// Need to open the file to trunc
	if (::FSpOpenDF(&mSpec, fsWrPerm, &refNum) != noErr)
		return NS_FILE_FAILURE;

	err = ::SetEOF(refNum, aNewLength);

